package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserTest {

    private File fileMock;
    private Charset charset;
    private CSVFormat formatMock;

    @BeforeEach
    void setUp() {
        fileMock = mock(File.class);
        charset = Charset.defaultCharset();
        formatMock = mock(CSVFormat.class);
    }

    @Test
    void parse_withValidFileCharsetAndFormat_shouldReturnCSVParserInstance() throws Exception {
        // Mock FileInputStream construction to avoid actual file IO
        try (MockedConstruction<FileInputStream> fisConstruction = Mockito.mockConstruction(FileInputStream.class)) {
            // Mock InputStreamReader construction to avoid actual IO
            try (MockedConstruction<InputStreamReader> isrConstruction = Mockito.mockConstruction(InputStreamReader.class,
                    (mock, context) -> {
                        // no-op
                    })) {
                CSVParser parser = CSVParser.parse(fileMock, charset, formatMock);
                assertNotNull(parser);
                // Assert internal fields via reflection
                var formatField = CSVParser.class.getDeclaredField("format");
                formatField.setAccessible(true);
                assertSame(formatMock, formatField.get(parser));
            }
        }
    }

    @Test
    void parse_withNullFile_shouldThrowNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, charset, formatMock);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_withNullFormat_shouldThrowNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(fileMock, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }
}
